+    #[test]
+    fn from_params_rejects_base_url_query_string() {
+        let err = DropboxConfig::from_params(&json!({
+            "access_token": "tok",
+            "base_url": "https://api.dropboxapi.com/2?leak=x",
+        }))
+        .unwrap_err();
+        match err {
+            FcpError::InvalidRequest { message, .. } => {
+                assert!(message.contains("base_url"), "got: {message}");
